// Generic content for zones without hyper-local data
function generateGenericIntro(zone: Zone): string {
  const isArrondissement = zone.department === "Paris";
  const locationType = isArrondissement ? "arrondissement" : "ville";
  const preposition = isArrondissement ? "dans le" : "a";

  return `Vous recherchez un specialiste de la porte sectionnelle ${preposition} ${zone.name} ? Notre entreprise intervient ${preposition} ${zone.name} et dans ses environs depuis plus de 25 ans pour l'installation, le depannage, la reparation et la motorisation de portes sectionnelles residentielles et industrielles. ${zone.name} est un${isArrondissement ? "" : "e " + locationType} ou les besoins en portes sectionnelles sont particulierement varies, entre immeubles residentiels, locaux commerciaux et zones d'activite. Nos techniciens qualifies connaissent parfaitement le parc immobilier de ${zone.name} et interviennent en urgence en moins de 30 minutes, 24 heures sur 24 et 7 jours sur 7. Que vous ayez besoin d'une installation neuve, d'un depannage urgent ou d'un contrat de maintenance, notre equipe est a votre disposition pour vous proposer la solution la plus adaptee a votre situation. Nous travaillons avec toutes les marques du marche (Hormann, Novoferm, Crawford, Came) et garantissons nos interventions. Contactez-nous au ${siteConfig.telephone} pour un devis gratuit et sans engagement.`;
}

function generateGenericExpertise(zone: Zone): string {
  const preposition = zone.department === "Paris" ? "dans le" : "a";

  return `Notre presence ${preposition} ${zone.name} depuis plus de 25 ans nous a permis d'acquerir une connaissance approfondie des specificites locales en matiere de porte sectionnelle. Nous intervenons aussi bien dans les immeubles residentiels que dans les locaux professionnels et les zones d'activite de ${zone.name}. Nos techniciens disposent de pieces de rechange pour toutes les marques et peuvent realiser la plupart des reparations en une seule visite, evitant ainsi les desagrements d'interventions multiples. Nous proposons des contrats de maintenance preventive adaptes aux coproprietes et aux entreprises, garantissant le bon fonctionnement de vos portes sectionnelles tout au long de l'annee. Notre equipe est formee aux dernieres technologies de motorisation et de domotique, et peut integrer votre porte sectionnelle dans votre systeme de gestion centralisee du batiment. Faites confiance a l'experience et au serieux de notre entreprise pour vos travaux de porte sectionnelle ${preposition} ${zone.name}.`;
}

// Helper: get zone index for template rotation
function getZoneIndex(zone: Zone): number {
  const allSlugs = Object.keys(localData);
  const idx = allSlugs.indexOf(zone.slug);
  return idx >= 0 ? idx : Math.abs(zone.slug.split("").reduce((a, c) => a + c.charCodeAt(0), 0)) % 6;
}

// Helper: safe access with fallback
function pick<T>(arr: T[], idx: number): T {
  return arr[idx % arr.length];
}

