type ContentFn = (zone: Zone, data: { landmarks: string[]; streets: string[]; neighborhoods: string[]; metros: string[] }, prep: string) => string;

const seo1Titles: ((zone: Zone, prep: string) => string)[] = [
  (zone, prep) => `Installation sur mesure de porte sectionnelle ${prep} ${zone.name}`,
  (zone, prep) => `Depannage urgent 24h/24 de porte sectionnelle ${prep} ${zone.name}`,
  (zone, prep) => `Securite et conformite CE de votre porte sectionnelle ${prep} ${zone.name}`,
  (zone, prep) => `Isolation thermique et performance energetique ${prep} ${zone.name}`,
  (zone, prep) => `Motorisation connectee et domotique ${prep} ${zone.name}`,
  (zone, prep) => `Materiaux et durabilite de votre porte sectionnelle ${prep} ${zone.name}`,
];

const seo1Templates: ContentFn[] = [
  // Template 0: INSTALLATION — etapes, materiaux, releves, types de panneaux
  (zone, data, prep) => `Poser une porte sectionnelle ${prep} ${zone.name} (${zone.postalCode}) mobilise un savoir-faire precis que nos monteurs exercent depuis plus de 25 ans sur le terrain. Avant toute intervention, un metreur se rend a votre adresse pres de ${data.landmarks[0]} pour relever au laser les cotes exactes de la baie, la profondeur du linteau, le retrait lateral disponible et la planeite du sol. Ces mesures determinent le choix du type de refoulement : plafond standard, a linteau reduit ou a refoulement lateral pour les configurations contraintes que l'on rencontre frequemment dans ${data.neighborhoods[0]}. Le cahier des charges integre le profil de panneau retenu — lisse, a nervures larges, a cassettes decoratives ou rainure M — ainsi que l'epaisseur souhaitee : 42 mm en double paroi acier-polyurethane pour un usage residentiel courant, ou 60 mm pour les locaux chauffes situes le long de ${data.streets[0]}. Le jour J, deux techniciens arrivent avec un fourgon charge de rails pre-debites, de panneaux filmes, de quincaillerie inox et du bloc-ressort calibre au poids exact du tablier. Ils fixent d'abord les rails verticaux au gros-oeuvre avec des chevilles chimiques, puis assemblent les panneaux un a un depuis le bas en clipsant les charnieres doubles. L'arbre de torsion est ensuite tendu au tour de cle pour equilibrer le tablier : un reglage que nos equipes effectuent quotidiennement pres de ${pick(data.streets, 1)} et dans ${pick(data.neighborhoods, 1)}. Enfin, la motorisation est raccordee, les telecommandes appairees et les fins de course ajustees. Un proces-verbal de reception atteste la conformite EN 13241-1 avant remise des cles.${data.metros.length > 0 ? ` Proches de ${data.metros[0]}, nos monteurs assurent un suivi rapide apres la mise en service.` : ""}`,

  // Template 1: DEPANNAGE URGENCE — 24/7, temps de reponse, pannes courantes, protocole
  (zone, data, prep) => `Un tablier immobilise en position basse a 7 h du matin, un ressort qui claque en pleine nuit, un moteur qui gronde sans entrainer la porte : ces urgences surviennent sans prevenir ${prep} ${zone.name} et exigent une reponse immediate. Notre cellule de crise, joignable au ${siteConfig.telephone} a toute heure, declenche l'envoi d'un depanneur equipe dans un rayon de 30 minutes autour de ${data.landmarks[0]}. Le protocole d'urgence se deroule en quatre temps distincts. Le technicien securise d'abord la zone : il bloque le tablier avec des serre-joints et coupe l'alimentation electrique pour eliminer tout risque dans votre garage de ${data.neighborhoods[0]}. Il procede ensuite a une inspection methodique des organes critiques : cables, tambours, galets, charnieres et paliers. Chaque anomalie est photographiee et consignee dans un rapport numerique transmis en temps reel. La troisieme phase est la reparation proprement dite : remplacement du ressort fracture, pose d'un cable neuf, echange du condensateur grille ou reprogrammation de la carte electronique. Nos fourgons qui sillonnent ${pick(data.streets, 0)} et ${pick(data.neighborhoods, 1)} transportent en permanence plus de 400 references de pieces — ressorts de 50 a 120 mm de diametre, cables acier de 3 a 5 mm, galets nylon et roulements a billes. La quatrieme etape consiste en un essai complet : dix cycles d'ouverture-fermeture, verification du debrayage manuel et controle des securites. Les habitants de ${pick(data.neighborhoods, 2)} le long de ${pick(data.streets, 1)} retrouvent ainsi l'acces a leur parking dans un delai garanti.${data.metros.length > 0 ? ` Nos equipes stationnees pres de ${pick(data.metros, 1)} couvrent l'ensemble du secteur sans temps mort.` : ""}`,

  // Template 2: SECURITE & NORMES — marquage CE, anti-intrusion, photocellules, aretes
  (zone, data, prep) => `Chaque porte sectionnelle installee ${prep} ${zone.name} doit satisfaire a un cadre reglementaire exigeant dont le pivot est la directive Machines 2006/42/CE, transposee par la norme harmonisee EN 13241-1. Nos techniciens qui interviennent pres de ${data.landmarks[0]} appliquent cette norme a la lettre en integrant cinq dispositifs de protection obligatoires. Le parachute anti-chute, fixe sur l'arbre de torsion, verrouille instantanement le tablier si un cable rompt — un composant vital dans les parkings a trafic soutenu de ${data.neighborhoods[0]}. Les cellules photoelectriques, installees a 25 cm du sol de part et d'autre de l'ouverture, creent un faisceau infrarouge invisible : toute coupure declenche l'inversion immediate du mouvement, protégeant pietions et vehicules le long de ${data.streets[0]}. La barre palpeuse pneumatique, encastree dans la traverse inferieure du tablier, detecte par compression la moindre resistance et coupe le moteur en 0,2 seconde. Le verrouillage anti-relevage, constitue de crochets en acier trempe ancres dans les rails, empeche toute tentative de soulevement exterieur — une securite anti-intrusion essentielle pour les biens stockes dans les garages de ${pick(data.neighborhoods, 1)}. Enfin, le limiteur d'effort electronique mesure en continu la force exercee par le moteur et stoppe la course si elle depasse 400 N, seuil fixe par la norme. Au-dela de ces equipements, les coproprietes de ${pick(data.neighborhoods, 2)} proches de ${pick(data.landmarks, 1)} doivent se conformer aux reglements locaux sur l'accessibilite PMR et la resistance au feu EI30 ou EI60. Notre bureau d'etudes verifie ces obligations en amont et delivre un dossier de conformite complet comprenant la declaration de performances, le marquage CE et le carnet de maintenance reglementaire.`,

  // Template 3: ISOLATION THERMIQUE — valeur R, economies, epaisseur, joints
  (zone, data, prep) => `La performance thermique d'une porte sectionnelle se mesure en coefficient de transmission U, et les ecarts entre modeles sont considerables — un parametre que les proprietaires ${prep} ${zone.name} sous-estiment souvent. Nos panneaux double paroi acier-polyurethane de 42 mm affichent un U de 1,2 W/m2K, tandis que la version 60 mm descend a 0,78 W/m2K, soit une resistance thermique R de 1,28 m2K/W. A titre comparatif, une porte basculante metallique depourvue d'isolant atteint un U de 5,8 W/m2K : la deperdition est cinq a sept fois superieure. Dans les garages attenants aux habitations de ${data.neighborhoods[0]}, cette difference se traduit par une reduction de 12 a 18 % de la facture de chauffage annuelle. L'etancheite peripherique joue un role tout aussi determinant. Nous posons un joint brosse en polypropylene sur chaque montant lateral, un joint a levre en EPDM sur le linteau et une bavette caoutchouc a double chambre au sol. Cet ensemble supprime les infiltrations d'air froid qui se glissent entre le cadre et le tablier, un defaut recurrent dans les installations vieillissantes le long de ${data.streets[0]}. Pour les locaux professionnels situes pres de ${data.landmarks[0]} ou la porte s'ouvre plusieurs dizaines de fois par jour, nous recommandons un seuil automatique a soufflet qui se comprime a la fermeture et se releve a l'ouverture, maintenant ainsi le pont thermique au minimum. Les residents de ${pick(data.neighborhoods, 1)} proches de ${pick(data.streets, 1)} qui souhaitent aller plus loin optent pour des panneaux a triple couche — acier, mousse PUR haute densite et aluminium interieur — qui atteignent un U record de 0,55 W/m2K. Nos techniciens evaluent lors de chaque visite ${prep} ${zone.name} le bilan thermique de votre garage et vous orientent vers l'epaisseur et les joints les mieux adaptes a votre consommation cible.${data.metros.length > 0 ? ` Depuis ${data.metros[0]}, ils rejoignent tout le secteur en quelques minutes pour un diagnostic gratuit.` : ""}`,

  // Template 4: MOTORISATION — marques Somfy/Hormann, smart home, telecommande, cycles
  (zone, data, prep) => `Automatiser votre porte sectionnelle ${prep} ${zone.name} ouvre l'acces a un ecosysteme technologique en constante evolution. Le moteur Somfy Dexxo Pro 1000 io, reference dans les coproprietes de ${data.neighborhoods[0]}, developpe 1 000 N de force de traction et enchaine jusqu'a 25 cycles par jour sans surchauffe grace a son variateur de vitesse electronique. Pour les portes de grand format presentes le long de ${data.streets[0]}, le Hormann SupraMatic HT offre 1 500 N et un fonctionnement a chaine renforcee concu pour 50 000 cycles — soit plus de douze ans d'usage intensif sans remplacement. Le moteur Came VER 13DMS, compact et silencieux a 38 dB, s'integre dans les garages a linteau bas frequents pres de ${data.landmarks[0]}. Au-dela du moteur lui-meme, la dimension connectee transforme l'experience utilisateur. Le module Somfy TaHoma Switch relie la porte au Wi-Fi domestique et permet l'ouverture depuis l'application mobile, la programmation de plages horaires et la creation de scenarios : par exemple, ouvrir la porte a 7 h 30 chaque matin et la verrouiller automatiquement a 22 h. Le protocole io-homecontrol chiffre les echanges radio en AES 128 bits, eliminant le risque de piratage de telecommande. Les residences de ${pick(data.neighborhoods, 1)} pres de ${pick(data.landmarks, 1)} adoptent de plus en plus le controle vocal via Alexa ou Google Home pour actionner la porte sans les mains. En copropriete dans ${pick(data.neighborhoods, 2)}, nous deployons des lecteurs de badge RFID Hexact et des cameras de lecture de plaque Hikvision qui autorisent l'ouverture uniquement aux vehicules enregistres. Chaque motorisation posee ${prep} ${zone.name} fait l'objet d'un appairage personnalise des telecommandes, d'un reglage fin des fins de course et d'un test de debrayage manuel pour les coupures de courant.`,

  // Template 5: DURABILITE & MATERIAUX — acier, aluminium, bois, corrosion, finitions
  (zone, data, prep) => `Le choix du materiau conditionne la longevite, l'esthetique et le comportement mecanique de votre porte sectionnelle ${prep} ${zone.name}. L'acier galvanise a chaud, traite par immersion dans un bain de zinc a 450 degres, constitue le standard industriel : sa couche protectrice de 275 g/m2 resiste a la corrosion pendant plus de 25 ans, meme dans les environnements urbains charges en dioxyde de soufre comme les abords de ${data.landmarks[0]}. Pour un rendu haut de gamme dans ${data.neighborhoods[0]}, l'acier recoit une laque polyester cuite au four en 200 teintes RAL — le gris anthracite RAL 7016 et le blanc signalisation RAL 9016 sont les plus demandes sur les facades des immeubles de ${data.streets[0]}. L'aluminium extruded, 60 % plus leger que l'acier a epaisseur egale, est privilegie pour les baies de tres grande dimension ou le poids du tablier sollicite fortement les ressorts et les rails. Sa resistance naturelle a l'oxydation le rend ideal pour les garages en rez-de-chaussee exposes aux intemperies pres de ${pick(data.streets, 1)}. Les panneaux a decor bois — chene dore, noyer sombre, sapin nordique — reproduisent fidelement les veinures du bois naturel par un film PVC lamine a haute definition, sans les contraintes d'entretien : ni ponçage, ni lasure, ni deformation par l'humidite. Ce revetement convainc les proprietaires de ${pick(data.neighborhoods, 1)} soucieux d'harmoniser la porte avec des menuiseries bois existantes. Pour les environnements industriels de ${pick(data.neighborhoods, 2)}, nous proposons des panneaux en acier prelaques de 60 mm d'epaisseur avec traitement anti-graffiti hydrophobe qui facilite le nettoyage haute pression. Chaque materiau est teste en chambre de brouillard salin selon la norme ISO 9227 avant validation, et nos techniciens ${prep} ${zone.name} vous presentent des echantillons grandeur nature lors de la visite technique pour un choix eclaire.${data.metros.length > 0 ? ` Nos equipes circulent regulierement a proximite de ${data.metros[0]} et apportent le panel complet d'echantillons a domicile.` : ""}`,
];

