const seo2Titles: ((zone: Zone, prep: string) => string)[] = [
  (zone, prep) => `Entretien preventif de votre porte sectionnelle ${prep} ${zone.name}`,
  (zone, prep) => `Quand remplacer votre porte sectionnelle ${prep} ${zone.name}`,
  (zone, prep) => `Porte sectionnelle ou porte basculante ${prep} ${zone.name} : le comparatif`,
  (zone, prep) => `Porte sectionnelle sur mesure pour batiments atypiques ${prep} ${zone.name}`,
  (zone, prep) => `Porte sectionnelle en copropriete et syndic ${prep} ${zone.name}`,
  (zone, prep) => `Economies d'energie et eco-responsabilite ${prep} ${zone.name}`,
];

const seo2Templates: ContentFn[] = [
  // Template 0: ENTRETIEN PREVENTIF — calendrier, lubrification, inspection ressorts
  (zone, data, prep) => `Anticiper les pannes plutot que les subir : voila la philosophie de notre programme d'entretien preventif pour les portes sectionnelles ${prep} ${zone.name}, secteur ${zone.postalCode}. Un contrat annuel engage deux visites semestrielles dans votre immeuble de ${data.neighborhoods[0]} ou votre local pres de ${data.landmarks[0]}. Lors de la premiere visite, programmee au printemps, le technicien realise un graissage integral de tous les axes mobiles : charnieres inter-panneaux, roulements de galets, paliers de l'arbre de torsion et glissieres du chariot moteur. Il applique une graisse au lithium haute temperature sur les pieces metalliques et un lubrifiant silicone sur les joints caoutchouc. La seconde visite, a l'automne, se concentre sur les organes de securite et de tension. Le dynamometre verifie que chaque ressort exerce une force egale des deux cotes du tablier — un desequilibre de plus de 5 % signale une fatigue du fil d'acier. Les cables sont examines toron par toron sur toute leur longueur, notamment aux points de frottement proches des tambours. Le technicien controle aussi l'aplomb des rails dans ${pick(data.neighborhoods, 1)} le long de ${data.streets[0]} : un ecart de plus de 2 mm par metre vertical provoque un frottement excessif des galets et accelere leur usure. Enfin, les cellules photoelectriques sont nettoyees et leur alignement verifie au laser. Les coproprietes de ${pick(data.neighborhoods, 2)} proches de ${pick(data.streets, 1)} beneficient d'un tarif degressif par porte et d'un acces prioritaire au service de depannage toute l'annee.${data.metros.length > 0 ? ` Nos techniciens bases pres de ${data.metros[0]} planifient les visites en circuit optimise pour garantir le respect des creneaux horaires convenus.` : ""}`,

  // Template 1: REMPLACEMENT — signes d'usure, quand changer, options de modernisation
  (zone, data, prep) => `Identifier le bon moment pour remplacer une porte sectionnelle ${prep} ${zone.name} evite des depannages a repetition qui finissent par couter plus cher qu'un equipement neuf. Plusieurs indices alertent nos techniciens lors de leurs passages dans ${data.neighborhoods[0]} : des panneaux gondoles ou fissures qui ne ferment plus hermetiquement, un tablier qui remonte de trois centimetres apres fermeture a cause de ressorts fatigues, des traces de rouille perforante sur les chants des panneaux le long de ${data.streets[0]}, ou un moteur qui peine a achever sa course en produisant un bourdonnement anormal. Quand le cumul des reparations depasse 40 % de la valeur d'une porte neuve, le remplacement integral devient l'option la plus rationnelle. Notre equipe de conseillers se rend a votre adresse pres de ${data.landmarks[0]} pour presenter les gammes de remplacement : modeles a isolation renforcee 60 mm pour les garages chauffes, portes a hublots panoramiques pour les ateliers, tabliers a finition micro-rainure pour les facades modernes de ${pick(data.neighborhoods, 1)}. La depose de l'ancienne installation et la pose de la nouvelle s'effectuent en une journee. Nous recyclons le tablier retire conformement a la reglementation DEEE et remettons au client un bordereau de suivi des dechets. Les proprietaires de ${pick(data.neighborhoods, 2)} le long de ${pick(data.streets, 1)} qui passent d'une basculante a une sectionnelle constatent une amelioration immediate du confort thermique et phonique. Pres de ${pick(data.landmarks, 1)}, nous avons modernise plus de 30 installations cette annee, chacune accompagnee d'une garantie decennale et d'une mise en service complete.`,

  // Template 2: PORTE SECTIONNELLE vs ALTERNATIVES — basculante, enroulable, battante
  (zone, data, prep) => `Comparer objectivement les types de portes de garage aide les proprietaires ${prep} ${zone.name} a investir de facon eclairee. La porte basculante, encore repandue dans les garages anciens de ${data.neighborhoods[0]}, bascule d'un seul tenant vers l'exterieur avant de se loger au plafond : ce debattement de 1,2 a 1,5 metre empiete sur le trottoir ou l'allee, une contrainte majeure dans les rues etroites proches de ${data.landmarks[0]}. La porte sectionnelle, composee de panneaux articules, monte verticalement puis glisse sous le plafond sans aucun debord exterieur. Cet avantage cinematique libere egalement 40 cm de profondeur interieure, un gain de rangement precieux le long de ${data.streets[0]}. En matiere d'isolation, l'ecart est net : un panneau sectionnelle sandwich de 42 mm offre un coefficient U de 1,2 W/m2K, contre 5,5 a 6,0 pour une basculante metallique non isolee. La porte enroulable a lames fines, parfois choisie dans les parkings de ${pick(data.neighborhoods, 1)} pour son faible encombrement vertical, presente une isolation mediocre (U de 3,5 W/m2K) et une resistance mecanique inferieure aux chocs de pare-chocs. La porte battante a deux vantaux, residuelle dans quelques pavillons de ${pick(data.neighborhoods, 2)}, impose un degagement frontal equivalent a la hauteur de la porte et ne peut pas etre motorisee de maniere fiable. Face a ces limites, la porte sectionnelle s'impose comme le meilleur compromis entre encombrement, isolation, robustesse et esthetique pour le parc immobilier de ${zone.name}. Nos conseillers techniques se deplacent avec des echantillons de panneaux et de lames pres de ${pick(data.landmarks, 1)} et dans ${pick(data.streets, 1)} pour une demonstration comparative gratuite.`,

  // Template 3: SOLUTIONS SUR MESURE — dimensions atypiques, bati ancien, couleurs
  (zone, data, prep) => `Les ouvertures non standards representent pres d'un tiers de nos chantiers ${prep} ${zone.name}, ou le bati ancien et les constructions atypiques imposent des configurations que les produits catalogue ne couvrent pas. Dans ${data.neighborhoods[0]}, les portes cocheres en plein cintre exigent un tablier dont le dernier panneau epouse la courbe de l'arc en pierre, avec un rail de guidage cintre sur mesure et des galets montes sur roulements excentriques. Les entrees de parking en pente, frequentes le long de ${data.streets[0]}, necessitent un ajustement angulaire du seuil et une bavette d'etancheite a profil oblique pour compenser le denivelé. Pres de ${data.landmarks[0]}, certaines baies depassent 5 metres de largeur : nous y installons des portes sectionnelles a double rail central et renforts transversaux en acier pour eviter toute flexion du tablier sous son propre poids. Les hauteurs sous plafond inferieures a 2,30 metres, courantes dans les sous-sols de ${pick(data.neighborhoods, 1)}, appellent un systeme a ressort arriere deporte qui n'occupe que 7 cm de linteau au lieu des 12 cm habituels. Le volet esthetique est tout aussi personnalisable : RAL sur mesure pour s'harmoniser avec la facade, grille de ventilation integree aux panneaux inferieurs, hublots rectangulaires en polycarbonate anti-UV. Les coproprietes historiques de ${pick(data.neighborhoods, 2)} proches de ${pick(data.landmarks, 1)} exigent parfois des habillages exterieurs en bois ou en fer forge qui masquent integralement la porte sectionnelle. Nous realisons ces habillages en atelier et les fixons sur le tablier sans alterer son fonctionnement mecanique ni son etancheite le long de ${pick(data.streets, 1)}.`,

  // Template 4: COPROPRIETE & SYNDIC — contrats collectifs, controle acces, badges
  (zone, data, prep) => `Administrer la porte de parking d'une copropriete ${prep} ${zone.name} implique des obligations reglementaires et des processus decisionnels que notre service dedie accompagne de bout en bout. Les syndics qui gerent des immeubles dans ${data.neighborhoods[0]} recoivent de notre part un dossier technique complet avant chaque assemblee generale : diagnostic de l'existant, propositions chiffrees en trois niveaux de prestations, planning previsionnel des travaux et modele de resolution a soumettre au vote. Une fois le mandat obtenu, notre equipe planifie l'intervention en concertation avec le gardien et les residents le long de ${data.streets[0]} pour minimiser la gene d'acces pendant le chantier. Le systeme de controle d'acces est un point central en copropriete. Nous deployons des lecteurs de badge RFID encastres dans le pilier, raccordes a une centrale qui memorise jusqu'a 500 utilisateurs. Chaque passage est horodate et consigne dans un journal consultable par le syndic depuis un portail web securise. Les immeubles de ${pick(data.neighborhoods, 1)} pres de ${data.landmarks[0]} adoptent de plus en plus la reconnaissance de plaque d'immatriculation, qui supprime le besoin de badge et fluidifie l'acces aux heures de pointe. En cas de panne bloquant l'acces au parking, notre astreinte 24 h/24 garantit une intervention en 30 minutes dans ${pick(data.neighborhoods, 2)}. Apres chaque passage, un rapport detaille — photos, mesures, pieces remplacees, preconisations — est envoye au syndic pres de ${pick(data.landmarks, 1)} sous format PDF signe electroniquement, facilitant l'archivage et le suivi pluriannuel le long de ${pick(data.streets, 1)}.`,

  // Template 5: ECONOMIES D'ENERGIE — pont thermique, facture chauffage, eco-responsabilite
  (zone, data, prep) => `Reduire l'empreinte energetique d'un batiment ${prep} ${zone.name} passe aussi par la porte de garage, souvent negligee dans les audits thermiques alors qu'elle constitue l'une des plus grandes ouvertures de l'enveloppe. Dans les immeubles de ${data.neighborhoods[0]}, une porte non isolee laisse s'echapper entre 15 et 25 kWh par metre carre et par an, soit l'equivalent de la consommation d'un radiateur electrique fonctionnant en continu. Le remplacement par une porte sectionnelle a panneaux polyurethane 42 mm ramene cette deperdition a 4 kWh/m2/an, une economie directement visible sur les charges de copropriete le long de ${data.streets[0]}. Les joints peripheriques — brosse laterale, levre EPDM superieure et bavette souple au sol — suppriment les circulations d'air parasite qui refroidissent les cages d'escalier attenantes aux parkings. A l'echelle d'un immeuble de 20 lots pres de ${data.landmarks[0]}, cette amelioration represente une reduction de 8 a 14 % de la facture collective de chauffage. Notre demarche eco-responsable ne s'arrete pas a l'isolation. Les portes en fin de vie retirees dans ${pick(data.neighborhoods, 1)} sont acheminées vers des filieres de recyclage certifiees : l'acier est refondu, la mousse polyurethane valorisee energetiquement, les composants electroniques traites selon la directive DEEE. Nous privilegions les fournisseurs europeens labellises ISO 14001 dont les usines situees en Allemagne et aux Pays-Bas reduisent l'empreinte carbone du transport. Les coproprietes de ${pick(data.neighborhoods, 2)} proches de ${pick(data.landmarks, 1)} qui s'engagent dans une renovation globale peuvent integrer le remplacement de la porte sectionnelle dans un bouquet de travaux eligible aux aides MaPrimeRenov et aux certificats d'economies d'energie le long de ${pick(data.streets, 1)}.${data.metros.length > 0 ? ` Nos conseillers, facilement accessibles depuis ${data.metros[0]}, realisent gratuitement le bilan energetique de votre porte actuelle.` : ""}`,
];

const seo2GenericTemplates: ((zone: Zone, prep: string) => string)[] = [
  // Generic 0: ENTRETIEN PREVENTIF
  (zone, prep) => `Anticiper les pannes plutot que les subir : notre programme d'entretien preventif ${prep} ${zone.name} (${zone.postalCode}) comprend deux visites semestrielles. Au printemps, graissage integral des axes mobiles — charnieres, galets, paliers et chariot moteur — avec graisse lithium haute temperature et lubrifiant silicone sur les joints. A l'automne, controle des organes de tension : dynamometre sur chaque ressort, examen toron par toron des cables aux points de frottement, verification de l'aplomb des rails au niveau a bulle. Les cellules photoelectriques sont nettoyees et realignees au laser. Tarif degressif pour les coproprietes et acces prioritaire au depannage toute l'annee ${prep} ${zone.name}.`,

  // Generic 1: REMPLACEMENT — signes d'usure, modernisation
  (zone, prep) => `Savoir quand remplacer plutot que reparer evite des depannages en cascade ${prep} ${zone.name}. Les signaux d'alerte : panneaux gondoles ou fissures, tablier qui remonte de plusieurs centimetres apres fermeture, rouille perforante sur les chants, moteur qui peine en fin de course. Quand le cumul des reparations depasse 40 % du prix d'une porte neuve, le remplacement integral s'impose. Depose et pose en une journee, recyclage du tablier conforme a la reglementation DEEE, bordereau de suivi des dechets remis au client. Garantie decennale sur chaque installation ${prep} ${zone.name}.`,

  // Generic 2: SECTIONNELLE vs ALTERNATIVES
  (zone, prep) => `Comparer objectivement les types de portes de garage aide a investir de facon eclairee ${prep} ${zone.name}. La basculante bascule d'un seul tenant avec un debord exterieur de 1,2 a 1,5 metre ; la sectionnelle monte verticalement sans aucun debattement, liberant 40 cm de profondeur interieure. Isolation : U de 1,2 W/m2K pour un panneau sectionnelle de 42 mm, contre 5,5 a 6,0 pour une basculante non isolee. L'enroulable a lames fines offre un faible encombrement mais une isolation mediocre (U de 3,5) et une resistance mecanique inferieure. La battante a deux vantaux impose un degagement frontal et ne se motorise pas de facon fiable. Demonstration comparative gratuite ${prep} ${zone.name} sur rendez-vous.`,

  // Generic 3: SOLUTIONS SUR MESURE — atypiques, bati ancien
  (zone, prep) => `Pres d'un tiers de nos chantiers ${prep} ${zone.name} concernent des ouvertures non standards. Les portes cocheres en plein cintre exigent un tablier epousant la courbe de l'arc avec un rail cintre et des galets excentriques. Les entrees en pente necessitent un seuil angulaire et une bavette a profil oblique. Les baies de plus de 5 metres recoivent un double rail central avec renforts transversaux. Les hauteurs sous plafond inferieures a 2,30 m appellent un ressort arriere deporte occupant seulement 7 cm de linteau. RAL sur mesure, grille de ventilation integree, hublots anti-UV et habillages exterieurs bois ou fer forge completent les possibilites de personnalisation ${prep} ${zone.name}.`,

  // Generic 4: COPROPRIETE & SYNDIC
  (zone, prep) => `Administrer la porte de parking d'une copropriete ${prep} ${zone.name} implique des obligations specifiques que notre service syndic accompagne integralement. Dossier technique pour l'assemblee generale : diagnostic, trois niveaux de devis, planning et modele de resolution. Controle d'acces par lecteurs RFID encastres memorisant 500 utilisateurs, journal horodate consultable en ligne, ou reconnaissance de plaque supprimant le besoin de badge. Astreinte 24 h/24 avec intervention en 30 minutes en cas de panne bloquant le parking. Rapport PDF signe electroniquement apres chaque passage ${prep} ${zone.name}.`,

  // Generic 5: ECONOMIES D'ENERGIE & ECO-RESPONSABILITE
  (zone, prep) => `Reduire l'empreinte energetique d'un batiment ${prep} ${zone.name} passe aussi par la porte de garage. Une porte non isolee laisse s'echapper 15 a 25 kWh/m2/an ; un panneau polyurethane 42 mm ramene cette deperdition a 4 kWh/m2/an. Les joints peripheriques suppriment les circulations d'air parasite qui refroidissent les cages d'escalier. A l'echelle d'un immeuble de 20 lots, la reduction atteint 8 a 14 % de la facture de chauffage collective. Les portes retirees sont recyclees — acier refondu, mousse valorisee energetiquement, electronique traitee selon la directive DEEE. Fournisseurs europeens ISO 14001. Bilan energetique gratuit ${prep} ${zone.name} sur demande.`,
];

